// Worked focus: httpsts-event-loop-lag-blocking — Distinguish asynchronous concurrency from parallelism and measure CPU blocking, synchronous I/O, long callbacks, and event-loop delay.
// Evidence: httpsts-worked-http-server-ts-concurrency-backpressure-workers-5
// Competency: httpsts-worked-http-server-ts-concurrency-backpressure-workers-5.
// Case 9036: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_concurrency_backpressure_workers_5(active: number, capacity: number, queueDepth: number, tenantTokens: number): { admit: boolean; offloadCpu: boolean; reason: string } {
  if (active < 0 || capacity <= 0 || queueDepth < 0) {
    return { admit: false, offloadCpu: false, reason: "invalid-budget" };
  }
  if (tenantTokens <= 0) return { admit: false, offloadCpu: false, reason: "tenant-rate" };
  const admit = active < capacity && queueDepth < capacity * 2;
  return { admit, offloadCpu: admit && active > capacity / 2, reason: admit ? "capacity" : "shed" };
}

